#include <bits/stdc++.h>
using namespace std;

// Finds the FIRST index in arr where arr[idx] >= target.
// Returns arr.size() if no such index exists.
// Precondition: arr is sorted ascending.
int lowerBoundManual(vector<int>& arr, int target) {
    int lo = 0, hi = (int)arr.size() - 1;
    int ans = (int)arr.size(); // default: not found
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2; // NEVER use (lo+hi)/2 — can overflow!
        if (arr[mid] >= target) {
            ans = mid;    // mid is a candidate; try to go further left
            hi = mid - 1;
        } else {
            lo = mid + 1;
        }
    }
    return ans;
}

// Finds the LAST index where arr[idx] <= target.
// Returns -1 if all elements are greater than target.
int upperBoundManual(vector<int>& arr, int target) {
    int lo = 0, hi = (int)arr.size() - 1;
    int ans = -1;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (arr[mid] <= target) {
            ans = mid;    // mid is a candidate; try to go further right
            lo = mid + 1;
        } else {
            hi = mid - 1;
        }
    }
    return ans;
}

int main() {
    vector<int> arr = {1, 3, 5, 7, 9, 11};

    cout << lowerBoundManual(arr, 5)  << "\n"; // 2 (index of 5)
    cout << lowerBoundManual(arr, 6)  << "\n"; // 3 (first >= 6 is 7)
    cout << lowerBoundManual(arr, 12) << "\n"; // 6 (past end)

    cout << upperBoundManual(arr, 7)  << "\n"; // 3 (index of 7)
    cout << upperBoundManual(arr, 8)  << "\n"; // 3 (last <= 8 is 7)
    cout << upperBoundManual(arr, 0)  << "\n"; // -1 (nothing <= 0)
    return 0;
}

