int main() {
    vector<int> v = {10, 20, 20, 30, 40, 40, 40, 50};

    // --- Count occurrences ---
    int cnt20 = upper_bound(v.begin(), v.end(), 20)
              - lower_bound(v.begin(), v.end(), 20); // 2
    int cnt40 = upper_bound(v.begin(), v.end(), 40)
              - lower_bound(v.begin(), v.end(), 40); // 3
    cout << cnt20 << " " << cnt40 << "\n"; // 2 3

    // --- Largest element <= query ---
    auto it = upper_bound(v.begin(), v.end(), 35);
    if (it != v.begin()) cout << *prev(it) << "\n"; // 30

    // --- Smallest element >= query ---
    auto it2 = lower_bound(v.begin(), v.end(), 25);
    if (it2 != v.end()) cout << *it2 << "\n"; // 30

    // --- Number of elements strictly less than query ---
    int less30 = lower_bound(v.begin(), v.end(), 30) - v.begin(); // 3
    cout << less30 << "\n";

    // --- Does value exist? ---
    cout << binary_search(v.begin(), v.end(), 20) << "\n"; // 1
    cout << binary_search(v.begin(), v.end(), 25) << "\n"; // 0

    // --- Member lower_bound on set (O(log n), not O(n)) ---
    set<int> s = {5, 10, 15, 20};
    auto sit = s.lower_bound(12); // iterator to 15
    cout << *sit << "\n"; // 15

    return 0;
}

#include <bits/stdc++.h>
using namespace std;

// Problem: n books with pages[i] pages each. Distribute to m students
// as contiguous segments. Minimise the maximum pages any student reads.

bool check(vector<int>& pages, int m, long long maxPages) {
    int students = 1;
    long long running = 0;
    for (int p : pages) {
        if ((long long)p > maxPages) return false; // single book exceeds cap
        if (running + p > maxPages) {
            students++;         // start a new student
            running = p;
            if (students > m) return false;
        } else {
            running += p;
        }
    }
    return true;
}

int main() {
    int n, m;
    cin >> n >> m;
    vector<int> pages(n);
    for (int& x : pages) cin >> x;

    // Search space: [max single book, sum of all books]
    long long lo = *max_element(pages.begin(), pages.end());
    long long hi = accumulate(pages.begin(), pages.end(), 0LL);
    long long ans = hi;

    while (lo <= hi) {
        long long mid = lo + (hi - lo) / 2;
        if (check(pages, m, mid)) {
            ans = mid;    // feasible — try to do better (smaller)
            hi = mid - 1;
        } else {
            lo = mid + 1; // not feasible — need a bigger cap
        }
    }
    cout << ans << "\n";
    return 0;
}
