#include <bits/stdc++.h>
using namespace std;

// Given n ropes of integer lengths, cut them all into pieces of length L.
// Find the maximum L such that you get at least k pieces.
bool canGet(vector<int>& ropes, int k, double L) {
    long long total = 0;
    for (int r : ropes) total += (long long)(r / L);
    return total >= k;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, k;
    cin >> n >> k;
    vector<int> ropes(n);
    for (int& r : ropes) cin >> r;

    double lo = 0, hi = *max_element(ropes.begin(), ropes.end());
    for (int iter = 0; iter < 100; iter++) { // 100 iterations ~ 30 decimal places
        double mid = (lo + hi) / 2.0;
        if (canGet(ropes, k, mid)) lo = mid;
        else hi = mid;
    }

    cout << fixed << setprecision(2) << lo << "\n";
    return 0;
}
// Input: 4 11   ropes: 802 743 457 539   =>  Output: 200.00

#include <bits/stdc++.h>
using namespace std;

int first(vector<int>& a, int t) {
    int lo = 0, hi = (int)a.size()-1, ans = -1;
    while (lo <= hi) {
        int mid = lo + (hi-lo)/2;
        if (a[mid] == t) { ans = mid; hi = mid-1; } // record, go left
        else if (a[mid] < t) lo = mid+1;
        else hi = mid-1;
    }
    return ans;
}

int last(vector<int>& a, int t) {
    int lo = 0, hi = (int)a.size()-1, ans = -1;
    while (lo <= hi) {
        int mid = lo + (hi-lo)/2;
        if (a[mid] == t) { ans = mid; lo = mid+1; } // record, go right
        else if (a[mid] < t) lo = mid+1;
        else hi = mid-1;
    }
    return ans;
}

int main() {
    vector<int> a = {2, 4, 4, 4, 6, 8, 8};
    cout << first(a, 4) << " " << last(a, 4) << "\n"; // 1 3
    cout << first(a, 8) << " " << last(a, 8) << "\n"; // 5 6
    cout << first(a, 5) << " " << last(a, 5) << "\n"; // -1 -1
    // STL equivalent:
    // count = upper_bound - lower_bound
    int cnt = upper_bound(a.begin(), a.end(), 4)
            - lower_bound(a.begin(), a.end(), 4); // 3
    cout << cnt << "\n";
    return 0;
}

