#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    long long k;
    cin >> n >> k;
    vector<long long> arr(n);
    for (auto& x : arr) cin >> x;
    sort(arr.begin(), arr.end());

    long long ans = 0;
    for (int i = 0; i < n - 1; i++) {
        long long limit = k - arr[i]; // need arr[j] < limit
        // lower_bound gives first index with arr[j] >= limit
        // everything before it satisfies arr[j] < limit
        auto it = lower_bound(arr.begin() + i + 1, arr.end(), limit);
        ans += (it - (arr.begin() + i + 1));
    }
    cout << ans << "\n";
    return 0;
}

