// n stalls at given positions. Place c cows into stalls such that the
// minimum distance between any two cows is MAXIMISED. Print that max distance.
// Constraints: 2 <= c <= n <= 1e5, 0 <= pos[i] <= 1e9
// Example: n=5 c=3, positions=[1,2,8,4,9] => answer = 3

sections.solution:
#include <bits/stdc++.h>
using namespace std;

bool check(vector<int>& pos, int c, int minDist) {
    int placed = 1, last = pos[0];
    for (int i = 1; i < (int)pos.size(); i++) {
        if (pos[i] - last >= minDist) {
            placed++;
            last = pos[i];
            if (placed == c) return true;
        }
    }
    return placed >= c;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, c;
    cin >> n >> c;
    vector<int> pos(n);
    for (int& x : pos) cin >> x;
    sort(pos.begin(), pos.end());

    int lo = 1, hi = pos.back() - pos.front();
    int ans = 0;
    while (lo <= hi) {
        int mid = lo + (hi - lo) / 2;
        if (check(pos, c, mid)) {
            ans = mid;    // feasible — try a larger minimum distance
            lo = mid + 1;
        } else {
            hi = mid - 1; // not feasible — need smaller distance
        }
    }
    cout << ans << "\n";
    return 0;
}

