// The M x N multiplication table has entry (i,j) = i*j for 1<=i<=M, 1<=j<=N.
// Find the k-th smallest value in this table.
// Constraints: 1 <= M, N <= 3e4, 1 <= k <= M*N
// Example: M=3 N=3 k=5 => 3
// Table sorted: 1,2,2,3,3,4,6,6,9

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    long long M, N, k;
    cin >> M >> N >> k;

    // How many table entries are <= x?
    auto countLE = [&](long long x) -> long long {
        long long total = 0;
        for (long long i = 1; i <= M; i++)
            total += min(x / i, N);
        return total;
    };

    long long lo = 1, hi = M * N, ans = hi;
    while (lo <= hi) {
        long long mid = lo + (hi - lo) / 2;
        if (countLE(mid) >= k) {
            ans = mid;
            hi = mid - 1; // try to find a smaller value that also satisfies
        } else {
            lo = mid + 1;
        }
    }
    cout << ans << "\n";
    return 0;
}
